// Step 0: Place new callout and wrap as alias
_CalloutsAction.default.placeCallout(500, 800).then(initialCalloutName => {
  const updatedText = `UpdatedCallout_${Date.now()}`;
  _CalloutsAction.default.saveCalloutsToServer();
  cy.reload();
  cy.wait(5000);
  _CalloutsAction.default.importCalloutsFromServer();
  // Step 3: Wait for the callout to appear before updating
  _CalloutsLocators.default.getCalloutsContainer.contains('span', initialCalloutName, {
    timeout: 10000
  }).should('be.visible').then(() => {
    // Now safely update
    _CalloutsAction.default.updateCallout(initialCalloutName, updatedText);
  });
  // Step 4: Save updated callouts
  _CalloutsAction.default.saveCalloutsToServer();
  // Step 5: Verify the updated callout text exists
  _CalloutsLocators.default.getCalloutsContainer.contains('span', updatedText, {
    timeout: 10000
  }).should('exist');
  _CalloutsAction.default.deleteCallout(updatedText);
});

